import{_ as e,c as d,o,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"버전 히스토리: 기능 발전 과정 | opencode-agent-skills","description":"OpenCode Agent Skills 플러그인의 버전 발전 히스토리를 학습하세요. 이 튜토리얼에서는 v0.1.0부터 v0.6.4까지의 모든 주요 기능 업데이트, 버그 수정, 아키텍처 개선 및 주요 변경 사항을 정리했습니다.","frontmatter":{"title":"버전 히스토리: 기능 발전 과정 | opencode-agent-skills","sidebarTitle":"새 버전 업데이트 내역","subtitle":"버전 히스토리","description":"OpenCode Agent Skills 플러그인의 버전 발전 히스토리를 학습하세요. 이 튜토리얼에서는 v0.1.0부터 v0.6.4까지의 모든 주요 기능 업데이트, 버그 수정, 아키텍처 개선 및 주요 변경 사항을 정리했습니다.","tags":["버전 업데이트","changelog","릴리스 히스토리"],"order":3},"headers":[],"relativePath":"ko/joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"ko/joshuadavidthomas/opencode-agent-skills/changelog/index.md"}'),l={name:"ko/joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function r(i,t,s,n,c,h){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="버전-히스토리" tabindex="-1">버전 히스토리 <a class="header-anchor" href="#버전-히스토리" aria-label="Permalink to &quot;버전 히스토리&quot;">​</a></h1><p>이 문서는 OpenCode Agent Skills 플러그인의 모든 버전 업데이트를 기록합니다. 버전 히스토리를 통해 기능의 발전 경로, 수정된 문제, 아키텍처 개선 사항을 확인할 수 있습니다.</p><div class="tip custom-block"><p class="custom-block-title">현재 버전</p><p>최신 안정 버전은 <strong>v0.6.4</strong> (2026-01-20)입니다.</p></div><h2 id="버전-타임라인" tabindex="-1">버전 타임라인 <a class="header-anchor" href="#버전-타임라인" aria-label="Permalink to &quot;버전 타임라인&quot;">​</a></h2><table tabindex="0"><thead><tr><th>버전</th><th>릴리스 날짜</th><th>유형</th><th>주요 내용</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>수정</td><td>YAML 파싱, Claude v2 지원</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>개선</td><td>스킬 추천 프롬프트 최적화</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>수정</td><td>스킬 이름과 디렉토리명 분리</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>개선</td><td>이미 로드된 스킬 중복 추천 방지</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>신규 기능</td><td>시맨틱 매칭, 임베딩 사전 계산</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>개선</td><td>퍼지 매칭 제안, 리팩토링</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>개선</td><td>설치 방식 간소화</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>개선</td><td>스크립트 재귀 검색</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>수정</td><td>심볼릭 링크 처리</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>수정</td><td>에이전트 모드 유지</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>수정</td><td>모델 전환 문제</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>신규 기능</td><td>파일 목록 기능</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>신규 기능</td><td>Superpowers 모드</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>초기</td><td>4개 도구, 다중 위치 탐색</td></tr></tbody></table><h2 id="상세-변경-기록" tabindex="-1">상세 변경 기록 <a class="header-anchor" href="#상세-변경-기록" aria-label="Permalink to &quot;상세 변경 기록&quot;">​</a></h2><h3 id="v0-6-4-2026-01-20" tabindex="-1">v0.6.4 (2026-01-20) <a class="header-anchor" href="#v0-6-4-2026-01-20" aria-label="Permalink to &quot;v0.6.4 (2026-01-20)&quot;">​</a></h3><p><strong>수정</strong>:</p><ul><li>스킬 다중 행 설명의 YAML frontmatter 파싱 수정(<code>|</code> 및 <code>&gt;</code> 블록 스칼라 구문 지원), 커스텀 파서를 <code>yaml</code> 라이브러리로 교체</li><li>Claude 플러그인 v2 형식 지원 추가, <code>installed_plugins.json</code>이 이제 단일 객체 대신 플러그인 설치 배열 사용</li></ul><p><strong>개선</strong>:</p><ul><li>Claude Code 플러그인 캐시 탐색이 새로운 중첩 디렉토리 구조 지원(<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>)</li></ul><h3 id="v0-6-3-2025-12-16" tabindex="-1">v0.6.3 (2025-12-16) <a class="header-anchor" href="#v0-6-3-2025-12-16" aria-label="Permalink to &quot;v0.6.3 (2025-12-16)&quot;">​</a></h3><p><strong>개선</strong>:</p><ul><li>스킬 평가 프롬프트 최적화로 모델이 사용자에게 &quot;스킬 불필요&quot; 메시지를 보내지 않도록 방지(사용자는 숨겨진 평가 프롬프트를 볼 수 없음)</li></ul><h3 id="v0-6-2-2025-12-15" tabindex="-1">v0.6.2 (2025-12-15) <a class="header-anchor" href="#v0-6-2-2025-12-15" aria-label="Permalink to &quot;v0.6.2 (2025-12-15)&quot;">​</a></h3><p><strong>수정</strong>:</p><ul><li>스킬 검증에서 디렉토리명이 SKILL.md frontmatter의 <code>name</code>과 다른 것을 허용. frontmatter의 <code>name</code>이 표준 식별자이며, 디렉토리명은 조직용으로만 사용. Anthropic Agent Skills 사양 준수.</li></ul><h3 id="v0-6-1-2025-12-13" tabindex="-1">v0.6.1 (2025-12-13) <a class="header-anchor" href="#v0-6-1-2025-12-13" aria-label="Permalink to &quot;v0.6.1 (2025-12-13)&quot;">​</a></h3><p><strong>개선</strong>:</p><ul><li>동적 스킬 추천이 세션별로 로드된 스킬을 추적하여 이미 로드된 스킬의 중복 추천 방지, 불필요한 프롬프트와 컨텍스트 사용 감소</li></ul><h3 id="v0-6-0-2025-12-12" tabindex="-1">v0.6.0 (2025-12-12) <a class="header-anchor" href="#v0-6-0-2025-12-12" aria-label="Permalink to &quot;v0.6.0 (2025-12-12)&quot;">​</a></h3><p><strong>추가</strong>:</p><ul><li><strong>시맨틱 스킬 매칭</strong>: 초기 스킬 목록 주입 후, 후속 메시지가 로컬 임베딩을 사용하여 스킬 설명과 매칭</li><li>로컬 임베딩 생성을 위한 <code>@huggingface/transformers</code> 의존성 추가(양자화된 all-MiniLM-L6-v2)</li><li>메시지가 사용 가능한 스킬과 매칭될 때 3단계 평가 프롬프트 주입(EVALUATE → DECIDE → ACTIVATE), 스킬 로딩 권장(<a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a>의 <a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">블로그 포스트</a>에서 영감)</li><li>저지연 매칭을 위한 임베딩 디스크 캐시(~/.cache/opencode-agent-skills/)</li><li><code>session.deleted</code> 이벤트에서 세션 정리</li></ul><h3 id="v0-5-0-2025-12-11" tabindex="-1">v0.5.0 (2025-12-11) <a class="header-anchor" href="#v0-5-0-2025-12-11" aria-label="Permalink to &quot;v0.5.0 (2025-12-11)&quot;">​</a></h3><p><strong>추가</strong>:</p><ul><li>모든 도구(<code>use_skill</code>, <code>read_skill_file</code>, <code>run_skill_script</code>, <code>get_available_skills</code>)에 &quot;혹시 이것을 찾으셨나요...&quot; 퍼지 매칭 제안 추가</li></ul><p><strong>개선</strong>:</p><ul><li><strong>Breaking Change</strong>: <code>find_skills</code> 도구를 <code>get_available_skills</code>로 이름 변경, 의도 명확화</li><li><strong>내부</strong>: 코드베이스를 독립 모듈로 재구성(<code>claude.ts</code>, <code>skills.ts</code>, <code>tools.ts</code>, <code>utils.ts</code>, <code>superpowers.ts</code>), 유지보수성 향상</li><li><strong>내부</strong>: AI 생성 주석 및 불필요한 코드 제거로 코드 품질 향상</li></ul><h3 id="v0-4-1-2025-12-08" tabindex="-1">v0.4.1 (2025-12-08) <a class="header-anchor" href="#v0-4-1-2025-12-08" aria-label="Permalink to &quot;v0.4.1 (2025-12-08)&quot;">​</a></h3><p><strong>개선</strong>:</p><ul><li>설치 방식이 git clone + 심볼릭 링크 대신 OpenCode config를 통한 npm 패키지 사용으로 변경</li></ul><p><strong>제거</strong>:</p><ul><li><code>INSTALL.md</code> 제거(설치 간소화 후 불필요)</li></ul><h3 id="v0-4-0-2025-12-05" tabindex="-1">v0.4.0 (2025-12-05) <a class="header-anchor" href="#v0-4-0-2025-12-05" aria-label="Permalink to &quot;v0.4.0 (2025-12-05)&quot;">​</a></h3><p><strong>개선</strong>:</p><ul><li>스크립트 탐색이 루트 디렉토리와 <code>scripts/</code> 하위 디렉토리만이 아닌 전체 스킬 디렉토리를 재귀 검색(최대 깊이 10)</li><li>스크립트가 기본 이름 대신 상대 경로(예: <code>tools/build.sh</code>)로 식별</li><li><code>read_skill_file</code>, <code>run_skill_script</code>, <code>use_skill</code> 도구에서 <code>skill_name</code> 매개변수를 <code>skill</code>로 이름 변경</li><li><code>run_skill_script</code> 도구에서 <code>script_name</code> 매개변수를 <code>script</code>로 이름 변경</li></ul><h3 id="v0-3-3-2025-12-02" tabindex="-1">v0.3.3 (2025-12-02) <a class="header-anchor" href="#v0-3-3-2025-12-02" aria-label="Permalink to &quot;v0.3.3 (2025-12-02)&quot;">​</a></h3><p><strong>수정</strong>:</p><ul><li><code>fs.stat</code> 사용으로 파일 및 디렉토리 감지 수정, 심볼릭 링크 올바르게 처리</li></ul><h3 id="v0-3-2-2025-11-30" tabindex="-1">v0.3.2 (2025-11-30) <a class="header-anchor" href="#v0-3-2-2025-11-30" aria-label="Permalink to &quot;v0.3.2 (2025-11-30)&quot;">​</a></h3><p><strong>수정</strong>:</p><ul><li>세션 시작 시 합성 메시지 주입 시 에이전트 모드 유지</li></ul><h3 id="v0-3-1-2025-11-28" tabindex="-1">v0.3.1 (2025-11-28) <a class="header-anchor" href="#v0-3-1-2025-11-28" aria-label="Permalink to &quot;v0.3.1 (2025-11-28)&quot;">​</a></h3><p><strong>수정</strong>:</p><ul><li><code>noReply</code> 액션에서 현재 모델을 명시적으로 전달하여 스킬 도구 사용 시 예기치 않은 모델 전환 수정(opencode issue #4475에 대한 임시 해결책)</li></ul><h3 id="v0-3-0-2025-11-27" tabindex="-1">v0.3.0 (2025-11-27) <a class="header-anchor" href="#v0-3-0-2025-11-27" aria-label="Permalink to &quot;v0.3.0 (2025-11-27)&quot;">​</a></h3><p><strong>추가</strong>:</p><ul><li><code>use_skill</code> 출력에 파일 목록 추가</li></ul><h3 id="v0-2-0-2025-11-26" tabindex="-1">v0.2.0 (2025-11-26) <a class="header-anchor" href="#v0-2-0-2025-11-26" aria-label="Permalink to &quot;v0.2.0 (2025-11-26)&quot;">​</a></h3><p><strong>추가</strong>:</p><ul><li>Superpowers 모드 지원 추가</li><li>릴리스 증명 추가</li></ul><h3 id="v0-1-0-2025-11-26" tabindex="-1">v0.1.0 (2025-11-26) <a class="header-anchor" href="#v0-1-0-2025-11-26" aria-label="Permalink to &quot;v0.1.0 (2025-11-26)&quot;">​</a></h3><p><strong>추가</strong>:</p><ul><li>스킬 콘텐츠를 컨텍스트에 로드하는 <code>use_skill</code> 도구 추가</li><li>스킬 디렉토리의 지원 파일을 읽는 <code>read_skill_file</code> 도구 추가</li><li>스킬 디렉토리에서 스크립트를 실행하는 <code>run_skill_script</code> 도구 추가</li><li>사용 가능한 스킬을 검색하고 나열하는 <code>find_skills</code> 도구 추가</li><li>다중 위치 스킬 탐색(프로젝트 레벨, 사용자 레벨, Claude 호환 위치)</li><li>Anthropic Agent Skills Spec v1.0 준수 frontmatter 검증</li><li>세션 시작 및 컨텍스트 압축 후 자동 스킬 목록 주입</li></ul><p><strong>신규 기여자</strong>:</p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (메인테이너)</li></ul><h2 id="기능-발전-개요" tabindex="-1">기능 발전 개요 <a class="header-anchor" href="#기능-발전-개요" aria-label="Permalink to &quot;기능 발전 개요&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능</th><th>도입 버전</th><th>발전 경로</th></tr></thead><tbody><tr><td>4개 기본 도구</td><td>v0.1.0</td><td>v0.5.0 퍼지 매칭 추가</td></tr><tr><td>다중 위치 스킬 탐색</td><td>v0.1.0</td><td>v0.4.1 설치 간소화, v0.6.4 Claude v2 지원</td></tr><tr><td>컨텍스트 자동 주입</td><td>v0.1.0</td><td>v0.3.0 파일 목록 추가, v0.6.1 중복 추천 방지</td></tr><tr><td>Superpowers 모드</td><td>v0.2.0</td><td>안정적 유지</td></tr><tr><td>스크립트 재귀 검색</td><td>v0.4.0</td><td>v0.3.3 심볼릭 링크 수정</td></tr><tr><td>시맨틱 매칭 추천</td><td>v0.6.0</td><td>v0.6.1 중복 방지, v0.6.3 프롬프트 최적화</td></tr><tr><td>퍼지 매칭 제안</td><td>v0.5.0</td><td>안정적 유지</td></tr></tbody></table><h2 id="주요-변경-사항-설명" tabindex="-1">주요 변경 사항 설명 <a class="header-anchor" href="#주요-변경-사항-설명" aria-label="Permalink to &quot;주요 변경 사항 설명&quot;">​</a></h2><h3 id="v0-6-0-시맨틱-매칭-기능" tabindex="-1">v0.6.0: 시맨틱 매칭 기능 <a class="header-anchor" href="#v0-6-0-시맨틱-매칭-기능" aria-label="Permalink to &quot;v0.6.0: 시맨틱 매칭 기능&quot;">​</a></h3><p>로컬 임베딩 기반 시맨틱 매칭 기능이 도입되어, AI가 사용자 메시지 내용에 따라 관련 스킬을 자동으로 추천할 수 있습니다. 사용자가 스킬 이름을 직접 기억할 필요가 없습니다.</p><ul><li><strong>기술 세부사항</strong>: HuggingFace의 <code>all-MiniLM-L6-v2</code> 모델(q8 양자화) 사용</li><li><strong>캐시 메커니즘</strong>: 임베딩 결과가 <code>~/.cache/opencode-agent-skills/</code>에 캐시되어 후속 매칭 속도 향상</li><li><strong>매칭 프로세스</strong>: 사용자 메시지 → 임베딩 → 스킬 설명과 코사인 유사도 계산 → Top 5 추천(임계값 0.35)</li></ul><h3 id="v0-5-0-리팩토링-및-도구-이름-변경" tabindex="-1">v0.5.0: 리팩토링 및 도구 이름 변경 <a class="header-anchor" href="#v0-5-0-리팩토링-및-도구-이름-변경" aria-label="Permalink to &quot;v0.5.0: 리팩토링 및 도구 이름 변경&quot;">​</a></h3><p>코드 아키텍처가 모듈화 설계로 리팩토링되었으며, 도구 이름이 더 명확해졌습니다:</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-스크립트-탐색-메커니즘-업그레이드" tabindex="-1">v0.4.0: 스크립트 탐색 메커니즘 업그레이드 <a class="header-anchor" href="#v0-4-0-스크립트-탐색-메커니즘-업그레이드" aria-label="Permalink to &quot;v0.4.0: 스크립트 탐색 메커니즘 업그레이드&quot;">​</a></h3><p>스크립트 탐색이 &quot;루트 디렉토리 + scripts/만&quot;에서 &quot;전체 스킬 디렉토리 재귀 검색&quot;(최대 깊이 10)으로 업그레이드되어, 더 유연한 스크립트 구성 방식을 지원합니다.</p><h3 id="v0-2-0-superpowers-통합" tabindex="-1">v0.2.0: Superpowers 통합 <a class="header-anchor" href="#v0-2-0-superpowers-통합" aria-label="Permalink to &quot;v0.2.0: Superpowers 통합&quot;">​</a></h3><p>Superpowers 워크플로우 모드 지원이 추가되었습니다. <code>using-superpowers</code> 스킬을 설치하고 환경 변수 <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code>를 설정해야 합니다.</p><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>라인</th></tr></thead><tbody><tr><td>현재 버전 번호</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>버전 히스토리</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>주요 버전 정보</strong>:</p><ul><li><code>v0.6.4</code>: 현재 버전 (2026-01-20)</li><li><code>v0.6.0</code>: 시맨틱 매칭 도입 (2025-12-12)</li><li><code>v0.5.0</code>: 리팩토링 버전 (2025-12-11)</li><li><code>v0.1.0</code>: 초기 버전 (2025-11-26)</li></ul></details>',72)])])}const v=e(l,[["render",r]]);export{p as __pageData,v as default};
